import{_ as a,c as o,o as t,a1 as r}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"付録: 設定リファレンスと移行 | oh-my-opencode","description":"oh-my-opencode の設定リファレンス、Claude Code 互換性ガイド、および組み込み MCP サーバーの使用方法を学びます。設定オプション、移行手順、検索機能の設定を理解し、Claude Code からのシームレスな移行を実現します。","frontmatter":{"title":"付録: 設定リファレンスと移行 | oh-my-opencode","sidebarTitle":"設定移行マスター","subtitle":"付録: 設定リファレンスと移行","description":"oh-my-opencode の設定リファレンス、Claude Code 互換性ガイド、および組み込み MCP サーバーの使用方法を学びます。設定オプション、移行手順、検索機能の設定を理解し、Claude Code からのシームレスな移行を実現します。","tags":["付録","リファレンス"],"order":170},"headers":[],"relativePath":"ja/code-yeongyu/oh-my-opencode/appendix/index.md","filePath":"ja/code-yeongyu/oh-my-opencode/appendix/index.md"}'),d={name:"ja/code-yeongyu/oh-my-opencode/appendix/index.md"};function i(l,e,n,s,h,c){return t(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="付録-リファレンス資料と互換性ガイド" tabindex="-1">付録：リファレンス資料と互換性ガイド <a class="header-anchor" href="#付録-リファレンス資料と互換性ガイド" aria-label="Permalink to &quot;付録：リファレンス資料と互換性ガイド&quot;">​</a></h1><p>本チャプターには <strong>oh-my-opencode</strong> の詳細なリファレンス資料と互換性ガイドが含まれており、完全な設定説明、Claude Code 移行サポート、および組み込み拡張サーバーの詳細な紹介を網羅しています。</p><h2 id="チャプター内容" tabindex="-1">チャプター内容 <a class="header-anchor" href="#チャプター内容" aria-label="Permalink to &quot;チャプター内容&quot;">​</a></h2><p>本チャプターには 3 つの重要なセクションが含まれています：</p><table tabindex="0"><thead><tr><th>サブページ</th><th>説明</th><th>難易度</th></tr></thead><tbody><tr><td><a href="./claude-code-compatibility/">Claude Code 互換性</a></td><td>Claude Code から OpenCode への完全な移行ガイド。Commands、Skills、Agents、MCPs、Hooks の互換メカニズムを含む</td><td>⭐⭐</td></tr><tr><td><a href="./configuration-reference/">設定リファレンス</a></td><td>oh-my-opencode 設定ファイルの完全な Schema 説明。すべてのフィールド、型、デフォルト値を網羅</td><td>⭐⭐⭐</td></tr><tr><td><a href="./builtin-mcps/">組み込み MCP</a></td><td>3 つの組み込み MCP サーバー（Exa Websearch、Context7、Grep.app）の機能と使用方法</td><td>⭐⭐</td></tr></tbody></table><h2 id="学習パスの推奨" tabindex="-1">学習パスの推奨 <a class="header-anchor" href="#学習パスの推奨" aria-label="Permalink to &quot;学習パスの推奨&quot;">​</a></h2><p>ニーズに応じて学習順序を選択してください：</p><h3 id="パス-1-claude-code-からの移行" tabindex="-1">パス 1：Claude Code からの移行 <a class="header-anchor" href="#パス-1-claude-code-からの移行" aria-label="Permalink to &quot;パス 1：Claude Code からの移行&quot;">​</a></h3><p>Claude Code から移行するユーザーの場合：</p><ol><li>まず <strong><a href="./claude-code-compatibility/">Claude Code 互換性</a></strong> を読み、既存の設定をシームレスに移行する方法を理解する</li><li>次に <strong><a href="./configuration-reference/">設定リファレンス</a></strong> を確認し、利用可能な設定オプションを深く理解する</li><li>最後に <strong><a href="./builtin-mcps/">組み込み MCP</a></strong> を学び、追加の検索機能を設定する方法を理解する</li></ol><h3 id="パス-2-高度なカスタマイズ" tabindex="-1">パス 2：高度なカスタマイズ <a class="header-anchor" href="#パス-2-高度なカスタマイズ" aria-label="Permalink to &quot;パス 2：高度なカスタマイズ&quot;">​</a></h3><p>oh-my-opencode の動作を高度にカスタマイズしたい場合：</p><ol><li><strong><a href="./configuration-reference/">設定リファレンス</a></strong> から始め、すべての設定可能項目を理解する</li><li><strong><a href="./builtin-mcps/">組み込み MCP</a></strong> を学び、検索とドキュメントクエリ機能を設定する</li><li><strong><a href="./claude-code-compatibility/">Claude Code 互換性</a></strong> を参照し、互換レイヤーの設定オプションを理解する</li></ol><h3 id="パス-3-クイックリファレンス" tabindex="-1">パス 3：クイックリファレンス <a class="header-anchor" href="#パス-3-クイックリファレンス" aria-label="Permalink to &quot;パス 3：クイックリファレンス&quot;">​</a></h3><p>特定の情報を確認するだけの場合：</p><ul><li><strong>設定に関する質問</strong> → 直接 <strong><a href="./configuration-reference/">設定リファレンス</a></strong> へ</li><li><strong>移行に関する質問</strong> → 直接 <strong><a href="./claude-code-compatibility/">Claude Code 互換性</a></strong> へ</li><li><strong>MCP 設定</strong> → 直接 <strong><a href="./builtin-mcps/">組み込み MCP</a></strong> へ</li></ul><h2 id="前提条件" tabindex="-1">前提条件 <a class="header-anchor" href="#前提条件" aria-label="Permalink to &quot;前提条件&quot;">​</a></h2><p>本チャプターを学習する前に、以下を完了していることを推奨します：</p><ul><li>✅ <strong><a href="./../start/installation/">インストールと設定</a></strong> を完了している</li><li>✅ <strong><a href="./../start/sisyphus-orchestrator/">Sisyphus オーケストレーター</a></strong> の基本概念を理解している</li><li>✅ JSON 設定ファイルの編集に慣れている</li></ul><h2 id="次のステップ" tabindex="-1">次のステップ <a class="header-anchor" href="#次のステップ" aria-label="Permalink to &quot;次のステップ&quot;">​</a></h2><p>本チャプターの学習を完了した後、以下のことができます：</p><ul><li>🚀 <strong><a href="./../advanced/">高度な機能</a></strong> を試し、より高度な使用方法を学ぶ</li><li>🔧 <strong><a href="./../faq/">よくある質問</a></strong> を確認し、使用中の問題を解決する</li><li>📖 <strong><a href="./../changelog/">更新履歴</a></strong> を読み、最新の機能改善を把握する</li></ul><div class="tip custom-block"><p class="custom-block-title">ヒント</p><p>本チャプターの内容は主にリファレンス資料として提供されており、順番に読む必要はありません。必要に応じて該当セクションを参照できます。</p></div>',23)])])}const g=a(d,[["render",i]]);export{u as __pageData,g as default};
